-- =============================================================

-- Proyecto Análisis de Ventas de Coches (Cars Dataset 2025)
-- Descripción: Carga de datos en las tablas del modelo dimensional
--   y limpieza de valores problemáticos detectados en el CSV original.
--
-- ORDEN DE EJECUCIÓN:
--   1. Dimensiones sin FK: dim_marca, dim_combustible, dim_customer,
--      dim_dealer, dim_salesperson
--   2. Dimensión con FK: dim_coche (depende de marca y combustible)
--   3. Tabla de hechos: fact_sales (depende de todas las dimensiones)

-- =============================================================

BEGIN;

-- dim_marca

-- dim_combustible

-- dim_coche

SELECT setval('dim_marca_marca_id_seq', 31);
SELECT setval('dim_combustible_combustible_id_seq', 7);
SELECT setval('dim_coche_coche_id_seq', 1218);-- dim_customer

-- dim_dealer

-- dim_salesperson

-- fact_sales

SELECT setval('fact_sales_sale_id_seq', 1000);


-- ===================================================================>
-- LIMPIEZA DE DATOS
-- Detectamos y corregimos problemas encontrados en el CSV original.
-- ===================================================================>

-- --------------------------------------------------------------------
-- 1. Valores Nulos en Precio
-- Algunos registros tienen precio_usd NULL porque el CSV tenía
-- rangos de precio ("$12,000-$15,000") o valores no parseables.
-- Los reemplazamos con la mediana del precio de su marca.
-- --------------------------------------------------------------------

-- Ver cuantos coches tienen precio nulo
SELECT COUNT(*) AS coches_sin_precio FROM dim_coche WHERE precio_usd IS NULL;

-- Actualizamos precio_usd nulo con el precio medio de la marca
UPDATE dim_coche dc
SET precio_usd = subq.precio_medio
FROM (
	SELECT marca_id, ROUND(AVG(precio_usd), 2) AS precio_medio
	FROM dim_coche
	WHERE precio_usd IS NOT NULL
	GROUP BY marca_id
) subq
WHERE dc.marca_id = subq.marca_id AND dc.precio_usd IS NULL;

-- Coches que siguen sin precio (marca sin ningún precio válido)
-- Los marcamos con un precio por defecto de 0 para no romper constraints
UPDATE dim_coche SET precio_usd = 0 WHERE precio_usd IS NULL;

-- --------------------------------------------------------------------
-- 1. Duplicados en dim_coche
-- El CSV puede tener el mismo modelo repetido con distinto caso o
-- espacios. Detectamos con RANK() PARTITION BY para identificar
-- duplicados sin borrar datos que podrían estar referenciados.
-- --------------------------------------------------------------------

-- Detectar duplicados potenciales (mismo marca_id y modelo en uppercase)
SELECT
	marca_id, 
	UPPER(TRIM(modelo)) AS modelo_normalizado,
	COUNT(*) AS total,
	RANK() OVER (PARTITION BY marca_id, UPPER(TRIM(modelo)) ORDER BY MIN(coche_id)) AS ranking
FROM dim_coche
GROUP BY marca_id, UPPER(TRIM(modelo))
HAVING COUNT(*) > 1
ORDER BY total DESC;

-- Nota: no borramos duplicados porque fact_sales puede referenciarlos.
-- En un sistema productivo se haría una fase de deduplicación antes
-- de cargar fact_sales.

-- --------------------------------------------------------------------
-- 3. Outliers en velocidad_max_kmh
-- Velocidades que no tienen sentido para un coche de calle.
-- --------------------------------------------------------------------

-- Ver posibles outliers (velocidad 0 o extremandamente alta)
SELECT coche_id, modelo, velocidad_max_kmh
FROM dim_coche
WHERE velocidad_max_kmh IS NOT NULL AND (velocidad_max_kmh < 50 OR velocidad_max_kmh > 500)
ORDER BY velocidad_max_kmh;

-- No sale ningún resultado, pero igualmente en caso de que los hubiera la query sería la siguiente.
-- Ponemos a NULL las velocidades claramente erróneas (< 50 o > 500 km/h)

UPDATE dim_coche
SET velocidad_max_kmh = NULL
WHERE velocidad_max_kmh IS NOT NULL 
AND (velocidad_max_kmh < 50 OR velocidad_max_kmh > 500);

-- --------------------------------------------------------------------
-- 4. Outliers en aceleracion_0_100
-- Aceleraciones negativas o absurdamente altas.
-- --------------------------------------------------------------------

SELECT coche_id, modelo, aceleracion_0_100
FROM dim_coche 
WHERE aceleracion_0_100 IS NOT NULL
AND (aceleracion_0_100 <= 0 OR aceleracion_0_100 > 30)
ORDER BY aceleracion_0_100;

-- Sale un resultado unicamente.
-- Ponemos a NULL las aceleraciones erróneas.

UPDATE dim_coche
SET aceleracion_0_100 = NULL
WHERE aceleracion_0_100 IS NOT NULL
AND (aceleracion_0_100  <= 0 OR aceleracion_0_100 > 30);

-- --------------------------------------------------------------------
-- 5. Aceleraciones nulas
-- Aquí eliminamos los campos que tienen aceleraciones nulas.
-- --------------------------------------------------------------------

-- Ver cuantos coches tienen aceleración nula
SELECT COUNT(*) AS coches_sin_acc
FROM dim_coche WHERE aceleracion_0_100 IS NULL;

-- Actualizamos aceleracion_0_100 nulo con la media de aceleración de su tipo de combustible.
UPDATE dim_coche dc
SET aceleracion_0_100 = subq.aceleracion_media
FROM (
	SELECT combustible_id, ROUND(AVG(aceleracion_0_100)::NUMERIC, 1) AS aceleracion_media
	FROM dim_coche
	WHERE aceleracion_0_100 IS NOT NULL
	GROUP BY combustible_id
) subq
WHERE dc.combustible_id = subq.combustible_id AND dc.aceleracion_0_100 IS NULL;

-- --------------------------------------------------------------------
-- 6. Normalización de marcas (case inconsistente en el csv)
-- En el CSV original convivían "NISSAN", "Nissan", "KIA", "Kia", "KIA "
-- Ya los normalizamos en la carga (todo a UPPERCASE en dim_marca),
-- pero verificamos que no quedó ninguno sin normalizar.
-- --------------------------------------------------------------------

SELECT nombre FROM dim_marca WHERE nombre != UPPER(TRIM(nombre));
-- Si devolviera filas (que no las devuelve) lo corregimos.
UPDATE dim_marca SET nombre = UPPER(TRIM(nombre))
WHERE nombre != UPPER(TRIM(nombre));

-- --------------------------------------------------------------------
-- 7. Ventas con total_price inconsistente
-- total_price debería ser igual a unit_price * quantity.
-- Detectamos discrepancias (margen de +-1$ por redondeos).
-- --------------------------------------------------------------------

SELECT sale_id, unit_price, quantity, total_price, ROUND(unit_price * quantity, 2) AS total_esperado
FROM fact_sales
WHERE ABS(total_price - ROUND(unit_price * quantity, 2)) > 1
ORDER BY sale_id;

-- En caso de que haya inconsistencias corregimos.
UPDATE fact_sales
SET total_price = ROUND(unit_price * quantity, 2)
WHERE ABS(total_price - ROUND(unit_price * quantity, 2)) > 1;

-- --------------------------------------------------------------------
-- 8. Ejemplo de delete
-- Eliminamos ventas con qunatity = 0 o negativos si las hubiera
-- (no debería haber por el CHECK de antes, pero lo validamos).
-- --------------------------------------------------------------------

DELETE FROM fact_sales WHERE quantity <= 0;

COMMIT;